const express = require('express');
const axios = require('axios');

const app = express();
const port = 3000;

app.use(express.json());

app.post('/verify-nin', async (req, res, next) => {
  const { number } = req.body;

  try {
    const response = await axios.post('https://api.prembly.com/verification/nin', {
      number: number
    }, {
      headers: {
        'app-id': process.env.PREMBLY_APP_ID,
        'x-api-key': process.env.PREMBLY_API_KEY
      }
    });

    res.json(response.data);
  } catch (error) {
    next(error);
  }
});

// Global Error Handling Middleware
app.use((err, req, res, next) => {
  let errorMessage = err.message;

  // If axios error, try to extract message from Prembly response
  if (err.response && err.response.data) {
    if (typeof err.response.data === 'string') {
        errorMessage = err.response.data;
    } else if (err.response.data.message) {
        errorMessage = err.response.data.message;
    } else if (err.response.data.error) {
        errorMessage = err.response.data.error;
    }
  }

  res.status(400).json({
    error: true,
    message: "Verification failed",
    details: errorMessage
  });
});

app.listen(port, () => {
  console.log(`Server running on port ${port}`);
});

